function patchUpdate(){let old=window.updateObjs;window.updateObjs=function(dt){if(old)old(dt);if(S){S._enemyGrid=null;if(S._perfTargets&&((S.time||0)>(S._perfTargetsAt||0))){S._perfTargets={};S._perfTargetsAt=(S.time||0)+.18}}trimWraithBlades();S._perfFarAt=(S._perfFarAt||0)-dt;if(S._perfFarAt<=0){S._perfFarAt=PERF.farCheck;recycleFarEnemies();S._enemyGrid=null}trimRuntimeLists();logPerfDiag(dt)}}
function patchDraw(){window.drawEnemies=function(){let total=S.enemies.length,rift31=isRiftRun()&&(S.rift.layer||1)>=31,showBars=!rift31&&total<90;for(const e of S.enemies){if(!visible(e,e.boss?220:PERF.drawMargin))continue;let base=e.boss?150:e.type==='slime'?(e.mini?34:58):e.type==='eye'||e.type==='healer'?48:e.type==='shield'||e.type==='charger'?50:42,scale=e.boss?1:e.type==='guardian'?1.12:e.type==='wraith'?1.08:e.elite&&e.type!=='shield'?1.06:1,sz=base*scale;if(e.boss){let breath=Math.sin(S.time*2)*.025;drawSheet(imgs[e.img||'boss'],e.x,e.y,sz,Math.floor((e.anim||0)*.7)%4,0,1+breath,1-breath)}else{let frame=Math.floor(e.anim||0)%4,bob=Math.sin((e.anim||0)*TAU/4)*1.4,stretch=e.type==='slime'?Math.sin((e.anim||0)*TAU/4)*.06:0;drawSheet(imgs[e.img||'imp'],e.x,e.y+bob,sz,frame,0,1+stretch,1-stretch)}let needBar=e.boss||e.elite||(!rift31&&(showBars||e.hit>0||e.hp<e.max*.92));if(needBar){drawBar(e,e.y-e.r-10,e.elite?'#a855f7':'#ef4444');if(e.shield>0){ctx.fillStyle='rgba(15,23,42,.85)';ctx.fillRect(e.x-e.r,e.y-e.r-17,e.r*2,4);ctx.fillStyle='#60a5fa';ctx.fillRect(e.x-e.r,e.y-e.r-17,e.r*2*clamp(e.shield/3,0,1),4)}}if(e.boss||e.elite||(!rift31&&total<120))drawEnemyStatus(e)}}}
function patchSkillShapeHits(){window.scytheArcAttack=function(target,dmg,range,arc,color='#c084fc',life=.28,fxKind='scytheArc'){let p=S.player,a=target?Math.atan2(target.y-p.y,target.x-p.x):Math.atan2(p.vy||0,p.vx||1),boost=1;if((S.relicLv.covenant||0)&&(S.reaperCharge||0)>=100){boost+=.38+S.relicLv.covenant*.06;S.reaperCharge=0;healPlayer(4+S.relicLv.covenant*2)}let hits=0,pool=nearbyEnemies(p.x,p.y,range+90);for(const m of pool){let dx=m.x-p.x,dy=m.y-p.y,d=Math.hypot(dx,dy),da=Math.atan2(Math.sin(Math.atan2(dy,dx)-a),Math.cos(Math.atan2(dy,dx)-a));if(d<range+(m.r||0)&&Math.abs(da)<arc/2){dealDamage(m,dmg*boost*(m.hp/m.max<.35?1.18+(S.relicLv.reap||0)*.06:1),true,'scytheArc');m.hit=.14;hits++}}S.artFx.push({x:p.x,y:p.y,type:'scytheArc',kind:fxKind,color,life,max:life,size:range*1.85,rot:a,arc});p.cast=.22;sfx('slash');return hits};window.slashAttack=function(kind,target,dmg,width,range,color,life=.24){let p=S.player,a=Math.atan2(target.y-p.y,target.x-p.x),ca=Math.cos(a),sa=Math.sin(a),ex=p.x+ca*range,ey=p.y+sa*range,hits=0,pool=nearbyEnemies((p.x+ex)/2,(p.y+ey)/2,range*.56+width+70);for(const m of pool){let px=m.x-p.x,py=m.y-p.y,along=px*ca+py*sa,side=Math.abs(px*sa-py*ca);if(along>0&&along<range&&side<width+(m.r||0)){dealDamage(m,dmg,true,modSkill(kind));m.hit=.12;hits++}}S.slashes.push({kind,x:(p.x+ex)/2,y:(p.y+ey)/2,life,max:life,rot:a,size:range,color});sfx('slash');return hits};window.beamAttack=function(kind,target,dmg,width,range,color,life=.22){let p=S.player,a=Math.atan2(target.y-p.y,target.x-p.x),ca=Math.cos(a),sa=Math.sin(a),ex=p.x+ca*range,ey=p.y+sa*range,hits=0,pool=nearbyEnemies((p.x+ex)/2,(p.y+ey)/2,range*.56+width+70);for(const m of pool){let px=m.x-p.x,py=m.y-p.y,along=px*ca+py*sa,side=Math.abs(px*sa-py*ca);if(along>0&&along<range&&side<width+(m.r||0)){dealDamage(m,dmg,true,modSkill(kind));m.hit=.1;hits++}}S.artFx.push({x:ex,y:ey,fromX:p.x,fromY:p.y,kind,type:kind,color,life,max:life,size:width*7,rot:a,beam:true});if(S.artifacts.includes('prism')&&target){let pp=nearbyEnemies(target.x,target.y,300),next=nearest(pp.filter(m=>m!==target&&dist(m,target)<260),target);if(next){let a2=Math.atan2(next.y-target.y,next.x-target.x);S.artFx.push({x:next.x,y:next.y,fromX:target.x,fromY:target.y,kind,type:kind,color,life,max:life,size:width*5,rot:a2,beam:true});dealDamage(next,dmg*.55,true,modSkill(kind))}}sfx('beam');return hits}}
